@Controller
class OidcController {
    private final OidcClientService oidcClientService;

    OidcController(OidcClientService oidcClientService) {
        this.oidcClientService = oidcClientService;
    }

    @GetMapping("/login")
    public ResponseEntity<Void> login(HttpServletRequest request) {
        String redirect = oidcClientService.buildAuthorizationRedirect(request.getSession(true));
        return ResponseEntity.status(HttpStatus.FOUND)
                .location(URI.create(redirect))
                .build();
    }

    @GetMapping("/oidc/callback")
    public ResponseEntity<String> callback(
            @RequestParam("code") String code,
            @RequestParam("state") String state,
            HttpServletRequest request
    ) {
        UserSession userSession = oidcClientService.handleCallback(code, state, request.getSession(true));
        return ResponseEntity.ok("Authenticated user: " + userSession.getUsername());
    }

    @GetMapping("/me")
    public ResponseEntity<?> me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Not authenticated");
        }
        UserSession userSession = (UserSession) session.getAttribute("USER_SESSION");
        if (userSession == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Not authenticated");
        }
        return ResponseEntity.ok(userSession);
    }

    @GetMapping("/logout")
    public ResponseEntity<String> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        return ResponseEntity.ok("Logged out");
    }
}

